// Список всех доменов для поиска
const DOMAINS = [
'Социальная алхимия', 'Микро-власть', 'Информационное выживание',
'Временная архитектура', 'Энергетический менеджмент', 'Психологический хакинг',
'Знаниевая инженерия', 'Контекстное программирование', 'Нарративный контроль',
'Метаигровое мышление', 'Эмоциональный джиу-джитсу', 'Туманная навигация',
'Конфликтная хореография', 'Племенная дипломатия', 'Калибровка интуиции',
'Стратегическое невежество', 'Селективная прозрачность', 'Опционное мышление',
'Латеральные прыжки', 'Разведка боем'
];

// Собираем историю + домены
const history = items
.map((item, index) => `${index + 1}. ${item.json.prompt_text}`)
.filter(text => text && text.trim() !== '')
.join('\n');

// Извлекаем домены из каждой идеи
const usedDomains = items.map(item => {
const text = item.json.prompt_text || '';
return DOMAINS.find(d => text.includes(d));
}).filter(Boolean);

// Последние 5 доменов (для запрета)
const last5Domains = usedDomains.slice(-5);

// Считаем использования каждого домена
const domainCount = {};
DOMAINS.forEach(d => domainCount[d] = 0);
usedDomains.forEach(d => domainCount[d] = (domainCount[d] || 0) + 1);

// Сортируем домены по частоте использования (редкие первыми)
const sortedDomains = DOMAINS
.map(d => ({ domain: d, count: domainCount[d] }))
.sort((a, b) => a.count - b.count)
.map(x => x.domain);

return [{
json: {
 history_text: history,
history_count: items.length,
 used_domains: usedDomains,
last_5_domains: last5Domains,
 allowed_domains: sortedDomains.slice(0, 5), // Топ-5 наименее использованных
 domain_usage_count: domainCount,
regeneration_count: 0
 }
}];

// Получаем текст ответа от критика
let responseText = $input.item.json.content[0].text;  // ← ДОБАВИЛИ [0]

// Убираем markdown обёртку если есть
responseText = responseText
  .replace(/^```json\n?/gm, '')
  .replace(/\n?```$/gm, '')
  .trim();

// Парсим JSON
const criticResponse = JSON.parse(responseText);

// Возвращаем объект с распакованными полями
return [{
  json: {
    ...($input.item.json),
    is_duplicate: criticResponse.is_duplicate,
    is_realistic: criticResponse.is_realistic !== undefined ? criticResponse.is_realistic : true,
    similarity_score: criticResponse.similarity_score,
    reason: criticResponse.reason,
    similar_to: criticResponse.similar_to,
    domain_detected: criticResponse.domain_detected,
    recommendation: criticResponse.recommendation
  }
}];

const today = new Date().toISOString().split('T')[0];
const userData = $('Find User by Chat ID').first().json;
const lastActivity = userData.last_activity_date;
const currentStreak = userData.streak_current || 0;
const recordStreak = userData.streak_record || 0;
const currentTotal = userData.total_completed || 0;

let newStreak = 1;

if (lastActivity) {
  const lastDate = new Date(lastActivity);
  const todayDate = new Date(today);
  const diffDays = Math.floor((todayDate - lastDate) / (1000 * 60 * 60 * 24));

  if (diffDays === 0) {
    newStreak = currentStreak;
  } else if (diffDays === 1) {
    newStreak = currentStreak + 1;
  } else {
    newStreak = 1;
  }
} else {
  newStreak = 1;
}

const newRecord = Math.max(newStreak, recordStreak);
const newTotal = currentTotal + 1;

// ОДИН return со ВСЕМИ данными
return [{
  json: {
    userId: userData.id,
    streak_current: newStreak,
    streak_record: newRecord,
    last_activity_date: today,
    total_completed: newTotal
  }
}];

// 15 вариантов ответов на добавление идеи
const responses = [
  "Записал ✓",
  "Готово ✓",
  "Принял 👌",
  "Сохранил",
  "Записал. До завтра!",
  "Принял. Увидимся завтра 👋",
  "Кайф, до завтра! ",
  "Сохранил. Завтра снова увидимся",
  "Круто. Завтра ещё поупражняемся",
  "Записал. До завтра 🚀",
  "Принято. До встречи!",
  "Зафиксировал ✓",
  "Готово. Завтра жду новых идей",
  "Сохранил. До скорого!"
];

// Выбираем случайный ответ
const randomResponse = responses[Math.floor(Math.random() * responses.length)];

return [{
  json: {
    message: randomResponse
  }
}];

const ideas = $("Get User's Ideas (7 days)").all();
const userData = $('Get All Active Users1').item.json;

// Проверяем, не сломана ли серия
const today = new Date();
const lastActivity = userData.last_activity_date;
let actualStreakCurrent = userData.streak_current || 0;

if (lastActivity) {
  const lastDate = new Date(lastActivity);
  const diffDays = Math.floor((today - lastDate) / (1000 * 60 * 60 * 24));

  if (diffDays > 1) {
    actualStreakCurrent = 0; // Серия сломана
  }
}

// Считаем метрики
const doneIdeas = ideas.filter(i => i.json.status === 'done');
const completedTasks = doneIdeas.length;
const totalWords = doneIdeas.reduce((sum, i) => {
  const text = i.json.user_answer || '';
  return sum + text.split(/\s+/).length;
}, 0);

const avgWords = completedTasks > 0 ? Math.round(totalWords / completedTasks) : 0;
const missedDays = 7 - completedTasks;

// Лучшее задание
const bestTask = doneIdeas.sort((a, b) => 
  (b.json.user_answer?.length || 0) - (a.json.user_answer?.length || 0)
)[0];

return [{
  json: {
    chat_id: userData.chat_id,
    userId: userData.id,
    streak_current: actualStreakCurrent, // ← ИСПОЛЬЗУЕМ ПРОВЕРЕННЫЙ STREAK
    streak_record: userData.streak_record || 0,
    avgWords: avgWords,
    avgWordsLast: userData.avg_word_count || 0,
    completedTasks: completedTasks,
    missedDays: missedDays,
    bestPrompt: bestTask?.json.prompt_text || 'Нет выполненных заданий',
    totalCompleted: userData.total_completed || 0
  }
}];

const taskText = $('AI generation new task').first().json.output || 
 $('AI regeneration').first().json.output;

const users = $('Merge').all();

return users.map(user => {
return {
  json: {
 id: user.json.id,
  chat_id: user.json.chat_id,
      task_text: taskText
    }
  };
 });

