const inputItem = $input.first();
 const historyText = inputItem.json.history_text || '';
 const historyLower = historyText.toLowerCase();

const domainCount = {};
Object.keys(DOMAINS).forEach(d => domainCount[d] = 0);

 for (const [domain, keywords] of Object.entries(DOMAINS)) {
  const matches = keywords.filter(k => historyLower.includes(k));
  domainCount[domain] = matches.length;
 }

const sortedDomains = Object.entries(domainCount)
 .sort((a, b) => a[1] - b[1])
  .slice(0, 3)
 .map(x => x[0]);

 return [{
 json: {
   ...inputItem.json,
   least_used_domains: sortedDomains.join(', '),
  domain_usage_count: domainCount
  }
 }];

